源码分析1 启动剖析我们就来看看 netty 中对下面的代码是怎样进行处理的
//1 netty 中使用 NioEventLoopGroup （简称 nio boss 线程）来封装线程和 selectorSelector selector = Selector.open(); //2 创建 NioServerSocketChannel，同时会初始化它关联的 handler，以及为原生 ssc 存储 configNioServerSocketChannel attachment = new NioServerSocketChannel();//3 创建 NioServerSocketChannel 时，创建了 java 原生的 ServerSocketChannelServerSocketChannel serverSocketChannel = ServerSocketChannel.open(); serverSocketChannel.configureBlocking(false);//4 启动 nio boss 线程执行接下来的操作//5 注册（仅关联 selector 和 NioServerSocketChannel），未关注事件SelectionKey selectionKey = serverSocketChannel.register(selector, 0, attachment);//6 head -&gt; 初始化器 -&gt; ServerBootstrapAcceptor -&gt; tail，初始化器是一次性的，只为添加 acceptor//7 绑定端口serverSocketChannel.bind(new InetSocketAddress(8080));//8 触发 channel active 事件，在 head 中关注 op_accept 事件selectionKey.interestOps(SelectionKey.OP_ACCEPT);

入口 io.netty.bootstrap.ServerBootstrap#bind
关键代码 io.netty.bootstrap.AbstractBootstrap#doBind
private ChannelFuture doBind(final SocketAddress localAddress) &#123;	// 1. 执行初始化和注册 regFuture 会由 initAndRegister 设置其是否完成，从而回调 3.2 处代码    final ChannelFuture regFuture = initAndRegister();    final Channel channel = regFuture.channel();    if (regFuture.cause() != null) &#123;        return regFuture;    &#125;    // 2. 因为是 initAndRegister 异步执行，需要分两种情况来看，调试时也需要通过 suspend 断点类型加以区分    // 2.1 如果已经完成    if (regFuture.isDone()) &#123;        ChannelPromise promise = channel.newPromise();        // 3.1 立刻调用 doBind0        doBind0(regFuture, channel, localAddress, promise);        return promise;    &#125;     // 2.2 还没有完成    else &#123;        final PendingRegistrationPromise promise = new PendingRegistrationPromise(channel);        // 3.2 回调 doBind0        regFuture.addListener(new ChannelFutureListener() &#123;            @Override            public void operationComplete(ChannelFuture future) throws Exception &#123;                Throwable cause = future.cause();                if (cause != null) &#123;                    // 处理异常...                    promise.setFailure(cause);                &#125; else &#123;                    promise.registered();					// 3. 由注册线程去执行（nioEventLoopGroup2-1） doBind0                    doBind0(regFuture, channel, localAddress, promise);                &#125;            &#125;        &#125;);        return promise;    &#125;&#125;

关键代码 io.netty.bootstrap.AbstractBootstrap#initAndRegister
final ChannelFuture initAndRegister() &#123;    Channel channel = null;    try &#123;        //创建一个NioServerSocketChannel        //底层和Nio的channel的构造方法是一样的，获取provider        channel = channelFactory.newChannel();         // 1.1 初始化 - 做的事就是添加一个初始化器 ChannelInitializer        init(channel);      &#125; catch (Throwable t) &#123;        // 处理异常...        return new DefaultChannelPromise(new FailedChannel(), GlobalEventExecutor.INSTANCE).setFailure(t);    &#125;    // 1.2 注册 - 做的事就是将原生 channel 注册到 selector 上    ChannelFuture regFuture = config().group().register(channel);    if (regFuture.cause() != null) &#123;        // 处理异常...    &#125;    return regFuture;&#125;

关键代码 io.netty.bootstrap.ServerBootstrap#init
// 这里 channel 实际上是 NioServerSocketChannelvoid init(Channel channel) throws Exception &#123;    final Map&lt;ChannelOption&lt;?&gt;, Object&gt; options = options0();    synchronized (options) &#123;        setChannelOptions(channel, options, logger);    &#125;    final Map&lt;AttributeKey&lt;?&gt;, Object&gt; attrs = attrs0();    synchronized (attrs) &#123;        for (Entry&lt;AttributeKey&lt;?&gt;, Object&gt; e: attrs.entrySet()) &#123;            @SuppressWarnings(&quot;unchecked&quot;)            AttributeKey&lt;Object&gt; key = (AttributeKey&lt;Object&gt;) e.getKey();            channel.attr(key).set(e.getValue());        &#125;    &#125;    ChannelPipeline p = channel.pipeline(); //nio的channel的流水线    final EventLoopGroup currentChildGroup = childGroup;    final ChannelHandler currentChildHandler = childHandler;    final Entry&lt;ChannelOption&lt;?&gt;, Object&gt;[] currentChildOptions;    final Entry&lt;AttributeKey&lt;?&gt;, Object&gt;[] currentChildAttrs;    synchronized (childOptions) &#123;        currentChildOptions = childOptions.entrySet().toArray(newOptionArray(0));    &#125;    synchronized (childAttrs) &#123;        currentChildAttrs = childAttrs.entrySet().toArray(newAttrArray(0));    &#125;	    // 为 NioServerSocketChannel 添加初始化器    p.addLast(new ChannelInitializer&lt;Channel&gt;() &#123;        @Override        public void initChannel(final Channel ch) throws Exception &#123;            final ChannelPipeline pipeline = ch.pipeline();            ChannelHandler handler = config.handler();            if (handler != null) &#123;                pipeline.addLast(handler);            &#125;            // 初始化器的职责是将 ServerBootstrapAcceptor 加入至 NioServerSocketChannel            ch.eventLoop().execute(new Runnable() &#123;                @Override                public void run() &#123;                    pipeline.addLast(new ServerBootstrapAcceptor(                            ch, currentChildGroup, currentChildHandler, currentChildOptions, currentChildAttrs));                &#125;            &#125;);        &#125;    &#125;);&#125;

关键代码 io.netty.channel.AbstractChannel.AbstractUnsafe#register
public final void register(EventLoop eventLoop, final ChannelPromise promise) &#123;    // 一些检查，略...    AbstractChannel.this.eventLoop = eventLoop;	// 检查当前线程是否是nioEventLoopGroup线程    if (eventLoop.inEventLoop()) &#123;        register0(promise);    &#125; else &#123;        try &#123;            // 首次执行 execute 方法时，会启动 nio 线程，之后注册等操作在 nio 线程上执行            // 因为只有一个 NioServerSocketChannel 因此，也只会有一个 boss nio 线程            // 这行代码完成的事实是 main -&gt; nio boss 线程的切换            eventLoop.execute(new Runnable() &#123;                @Override                public void run() &#123;                    register0(promise);                &#125;            &#125;);        &#125; catch (Throwable t) &#123;            // 日志记录...            closeForcibly();            closeFuture.setClosed();            safeSetFailure(promise, t);        &#125;    &#125;&#125;



io.netty.channel.AbstractChannel.AbstractUnsafe#register0
private void register0(ChannelPromise promise) &#123;    try &#123;        if (!promise.setUncancellable() || !ensureOpen(promise)) &#123;            return;        &#125;        boolean firstRegistration = neverRegistered;        // 1.2.1 原生的 nio channel 绑定到 selector 上，注意此时没有注册 selector 关注事件，附件为 NioServerSocketChannel        doRegister();        neverRegistered = false;        registered = true;        // 1.2.2 执行 NioServerSocketChannel 初始化器的 initChannel        pipeline.invokeHandlerAddedIfNeeded();        // 回调 3.2 io.netty.bootstrap.AbstractBootstrap#doBind0        // 这里的promise其实就是之前的regFuture对象        safeSetSuccess(promise); //给promise对象设置一个成功的结果        pipeline.fireChannelRegistered();                // 对应 server socket channel 还未绑定，isActive 为 false        if (isActive()) &#123;            if (firstRegistration) &#123;                pipeline.fireChannelActive();            &#125; else if (config().isAutoRead()) &#123;                beginRead();            &#125;        &#125;    &#125; catch (Throwable t) &#123;        // Close the channel directly to avoid FD leak.        closeForcibly();        closeFuture.setClosed();        safeSetFailure(promise, t);    &#125;&#125;

关键代码 io.netty.channel.ChannelInitializer#initChannel
private boolean initChannel(ChannelHandlerContext ctx) throws Exception &#123;    if (initMap.add(ctx)) &#123; // Guard against re-entrance.        try &#123;            // 1.2.2.1 执行初始化            initChannel((C) ctx.channel());        &#125; catch (Throwable cause) &#123;            exceptionCaught(ctx, cause);        &#125; finally &#123;            // 1.2.2.2 移除初始化器            ChannelPipeline pipeline = ctx.pipeline();            if (pipeline.context(this) != null) &#123;                pipeline.remove(this);            &#125;        &#125;        return true;    &#125;    return false;&#125;

关键代码 io.netty.bootstrap.AbstractBootstrap#doBind0
// 3.1 或 3.2 执行 doBind0private static void doBind0(        final ChannelFuture regFuture, final Channel channel,        final SocketAddress localAddress, final ChannelPromise promise) &#123;    channel.eventLoop().execute(new Runnable() &#123;        @Override        public void run() &#123;            if (regFuture.isSuccess()) &#123;                channel.bind(localAddress, promise).addListener(ChannelFutureListener.CLOSE_ON_FAILURE);            &#125; else &#123;                promise.setFailure(regFuture.cause());            &#125;        &#125;    &#125;);&#125;

关键代码 io.netty.channel.AbstractChannel.AbstractUnsafe#bind
public final void bind(final SocketAddress localAddress, final ChannelPromise promise) &#123;    assertEventLoop();    if (!promise.setUncancellable() || !ensureOpen(promise)) &#123;        return;    &#125;    if (Boolean.TRUE.equals(config().getOption(ChannelOption.SO_BROADCAST)) &amp;&amp;        localAddress instanceof InetSocketAddress &amp;&amp;        !((InetSocketAddress) localAddress).getAddress().isAnyLocalAddress() &amp;&amp;        !PlatformDependent.isWindows() &amp;&amp; !PlatformDependent.maybeSuperUser()) &#123;        // 记录日志...    &#125;    boolean wasActive = isActive();    try &#123;        // 3.3 执行端口绑定        doBind(localAddress);    &#125; catch (Throwable t) &#123;        safeSetFailure(promise, t);        closeIfClosed();        return;    &#125;    if (!wasActive &amp;&amp; isActive()) &#123; // 判断是不是active状态        invokeLater(new Runnable() &#123;            @Override            public void run() &#123;                // 3.4 触发 active 事件                pipeline.fireChannelActive();            &#125;        &#125;);    &#125;    safeSetSuccess(promise);&#125;

3.3 关键代码 io.netty.channel.socket.nio.NioServerSocketChannel#doBind
protected void doBind(SocketAddress localAddress) throws Exception &#123;    if (PlatformDependent.javaVersion() &gt;= 7) &#123;        javaChannel().bind(localAddress, config.getBacklog());    &#125; else &#123;        javaChannel().socket().bind(localAddress, config.getBacklog());    &#125;&#125;

3.4 关键代码 io.netty.channel.DefaultChannelPipeline.HeadContext#channelActive
public void channelActive(ChannelHandlerContext ctx) &#123;    ctx.fireChannelActive();	// 触发 read (NioServerSocketChannel 上的 read 不是读取数据，只是为了触发 channel 的事件注册)    readIfIsAutoRead();&#125;

关键代码 io.netty.channel.nio.AbstractNioChannel#doBeginRead
protected void doBeginRead() throws Exception &#123;    // Channel.read() or ChannelHandlerContext.read() was called    final SelectionKey selectionKey = this.selectionKey;    if (!selectionKey.isValid()) &#123;        return;    &#125;    readPending = true;    final int interestOps = selectionKey.interestOps();    // readInterestOp 取值是 16，在 NioServerSocketChannel 创建时初始化好，代表关注 accept 事件    if ((interestOps &amp; readInterestOp) == 0) &#123;        selectionKey.interestOps(interestOps | readInterestOp);    &#125;&#125;

流程：

2  NioEventLoop 剖析
NioEventLoop的重要组成：selector、线程和任务队列。

（1）selectorio/netty/channel/nio/NioEventLoop
private Selector selector;  private Selector unwrappedSelector;

（2）线程和任务队列io/netty/util/concurrent/SingleThreadEventExecutor 
private final Queue&lt;Runnable&gt; taskQueue;private volatile Thread thread;

io/netty/util/concurrent/AbstractScheduledEventExecutor
PriorityQueue&lt;ScheduledFutureTask&lt;?&gt;&gt; scheduledTaskQueue;


selector何时创建？
​	在构造方法调用时，selector就被创建了。

io/netty/channel/nio/NioEventLoop
NioEventLoop(NioEventLoopGroup parent, Executor executor, SelectorProvider selectorProvider,                SelectStrategy strategy, RejectedExecutionHandler rejectedExecutionHandler,                EventLoopTaskQueueFactory queueFactory) &#123;       super(parent, executor, false, newTaskQueue(queueFactory), newTaskQueue(queueFactory),               rejectedExecutionHandler);       this.provider = ObjectUtil.checkNotNull(selectorProvider, &quot;selectorProvider&quot;);       this.selectStrategy = ObjectUtil.checkNotNull(strategy, &quot;selectStrategy&quot;);       final SelectorTuple selectorTuple = openSelector(); // 创建selector对象       this.selector = selectorTuple.selector;       this.unwrappedSelector = selectorTuple.unwrappedSelector;   &#125;

private SelectorTuple openSelector() &#123;       final Selector unwrappedSelector;       try &#123;           // 创建selector对象，本质上和nio中的selector的创建方式是一样的，都是通过provider创建的           unwrappedSelector = provider.openSelector();        &#125; catch (IOException e) &#123;           throw new ChannelException(&quot;failed to open a new selector&quot;, e);       &#125;       ...   &#125;

Nio中selector的创建方式如下java/nio/channels/Selector.java
public static Selector open() throws IOException &#123;       return SelectorProvider.provider().openSelector();   &#125;


eventLoop为什么有两个selector成员？

io/netty/channel/nio/NioEventLoop
private SelectorTuple openSelector() &#123;       final Selector unwrappedSelector;       try &#123;           // 实际上，unwrappedSelector才是EventLoop中真正的selector           // 那么另一个selector是什么作用呢？           unwrappedSelector = provider.openSelector();        &#125; catch (IOException e) &#123;           throw new ChannelException(&quot;failed to open a new selector&quot;, e);       &#125;       ...   &#125;

实际上，EventLoop的selector内部有一个SelectionKey的集合，我们监听的事件需要从这个集合中获取事件的信息。
Set集合的遍历性能比较差，需要遍历每个哈希桶，每个桶中还有各个链表。
public abstract Set&lt;SelectionKey&gt; keys();

这里的selector就是将原本的unwrappedSelector的Set实现给替换成了数组，因为数组的遍历效率比Set的高，但是在其它的地方还需要用到Set，所以Netty中的EventLoop就维护了两个selector，就是为了优化selectionnKey的遍历。

eventLoop的nio线程在何时启动？
​	当首次调用execute方法时，nio线程就会被启动。
​	通过一个状态位控制保证nio线程只会被启动一次。

我们写一个测试案例，通过debug模式来查看Nio线程启动的过程。
public class Main &#123;    public static void main(String[] args) &#123;        EventLoop eventLoop = new NioEventLoopGroup().next();        eventLoop.execute(() -&gt; &#123; //在此处打一个断点，debug查看            System.out.println(&quot;hello&quot;);        &#125;);    &#125;&#125;

debug模式下，给出截图作为流程：





提交普通任务时会不会结束select的阻塞？
​	会的，而且会很及时的调用selector.wakeup()将其唤醒。

io/netty/channel/nio/NioEventLoop.java
private int select(long deadlineNanos) throws IOException &#123;       if (deadlineNanos == NONE) &#123;           return selector.select();       &#125;       // Timeout will only be 0 if deadline is within 5 microsecs       long timeoutMillis = deadlineToDelayNanos(deadlineNanos + 995000L) / 1000000L;       //selector.select(timeoutMillis)       //selector(timeoutMillis)与Nio的selector()方法有点区别       //timeoutMillis超时时间，如果超过这个时间，就会结束阻塞       return timeoutMillis &lt;= 0 ? selector.selectNow() : selector.select(timeoutMillis);   &#125;


wakeup变量的作用

@Override    protected void wakeup(boolean inEventLoop) &#123;        if (!inEventLoop &amp;&amp; nextWakeupNanos.getAndSet(AWAKE) != AWAKE) &#123;            // !inEventLoop  只有其他线程提交任务时，才会调用wakeup()方法            // nextWakeupNanos.getAndSet(AWAKE) != AWAKE 如果有多个其他线程同时提交任务，唤醒其中一个线程即可，即保证在多线程下保证只有一个线程执行wakeup()方法            selector.wakeup(); //wakeup方法是重量级的操作，所以我们要避免频繁调用该方法        &#125;    &#125;


每次循环时，什么时候会进入SelectorStrategy.SELECT分支？
当没有任务时，会进入SelectorStrategy.SELECT

io/netty/channel/DefaultSelectStrategy.java

当有任务时，即hasTasks为true，会进入get()方法，拿到IO事件和任务，交给下面的线程来处理。

何时会selector阻塞，会阻塞多久呢 ？




NioEventLoop 线程不仅要处理 IO 事件，还要处理 Task（包括普通任务和定时任务

提交任务代码 io.netty.util.concurrent.SingleThreadEventExecutor#execute
public void execute(Runnable task) &#123;    if (task == null) &#123;        throw new NullPointerException(&quot;task&quot;);    &#125;    boolean inEventLoop = inEventLoop();    // 添加任务，其中队列使用了 jctools 提供的 mpsc 无锁队列    addTask(task);    if (!inEventLoop) &#123;        // inEventLoop 如果为 false 表示由其它线程来调用 execute，即首次调用，这时需要向 eventLoop 提交首个任务，启动死循环，会执行到下面的 doStartThread        startThread();        if (isShutdown()) &#123;            // 如果已经 shutdown，做拒绝逻辑，代码略...        &#125;    &#125;    if (!addTaskWakesUp &amp;&amp; wakesUpForTask(task)) &#123;        // 如果线程由于 IO select 阻塞了，添加的任务的线程需要负责唤醒 NioEventLoop 线程        wakeup(inEventLoop);    &#125;&#125;

唤醒 select 阻塞线程io.netty.channel.nio.NioEventLoop#wakeup
@Overrideprotected void wakeup(boolean inEventLoop) &#123;    if (!inEventLoop &amp;&amp; wakenUp.compareAndSet(false, true)) &#123;        selector.wakeup();    &#125;&#125;

启动 EventLoop 主循环 io.netty.util.concurrent.SingleThreadEventExecutor#doStartThread
private void doStartThread() &#123;    assert thread == null;    executor.execute(new Runnable() &#123;        @Override        public void run() &#123;            // 将线程池的当前线程保存在成员变量中，以便后续使用            thread = Thread.currentThread();            if (interrupted) &#123;                thread.interrupt();            &#125;            boolean success = false;            updateLastExecutionTime();            try &#123;                // 调用外部类 SingleThreadEventExecutor 的 run 方法，进入死循环，run 方法见下                SingleThreadEventExecutor.this.run();                success = true;            &#125; catch (Throwable t) &#123;                logger.warn(&quot;Unexpected exception from an event executor: &quot;, t);            &#125; finally &#123;				// 清理工作，代码略...            &#125;        &#125;    &#125;);&#125;


nio空轮询bug在哪里出现，如何解决？

io.netty.channel.nio.NioEventLoop#select
private void select(boolean oldWakenUp) throws IOException &#123;    Selector selector = this.selector;    try &#123;        int selectCnt = 0;        long currentTimeNanos = System.nanoTime();        // 计算等待时间        // * 没有 scheduledTask，超时时间为 1s        // * 有 scheduledTask，超时时间为 `下一个定时任务执行时间 - 当前时间`        long selectDeadLineNanos = currentTimeNanos + delayNanos(currentTimeNanos);        for (;;) &#123;            long timeoutMillis = (selectDeadLineNanos - currentTimeNanos + 500000L) / 1000000L;            // 如果超时，退出循环            if (timeoutMillis &lt;= 0) &#123;                if (selectCnt == 0) &#123;                    selector.selectNow();                    selectCnt = 1;                &#125;                break;            &#125;            // 如果期间又有 task 退出循环，如果没这个判断，那么任务就会等到下次 select 超时时才能被执行            // wakenUp.compareAndSet(false, true) 是让非 NioEventLoop 不必再执行 wakeup            if (hasTasks() &amp;&amp; wakenUp.compareAndSet(false, true)) &#123;                selector.selectNow();                selectCnt = 1;                break;            &#125;            // select 有限时阻塞            // 注意 nio 有 bug，当 bug 出现时，select 方法即使没有时间发生，也不会阻塞住，导致不断空轮询，cpu 占用 100%            // jdk在linux下才会出现空轮询bug            int selectedKeys = selector.select(timeoutMillis);            // 计数加 1            selectCnt ++;            // 醒来后，如果有 IO 事件、或是由非 EventLoop 线程唤醒，或者有任务，退出循环            if (selectedKeys != 0 || oldWakenUp || wakenUp.get() || hasTasks() || hasScheduledTasks()) &#123;                break;            &#125;            if (Thread.interrupted()) &#123;               	// 线程被打断，退出循环                // 记录日志                selectCnt = 1;                break;            &#125;            long time = System.nanoTime();            if (time - TimeUnit.MILLISECONDS.toNanos(timeoutMillis) &gt;= currentTimeNanos) &#123;                // 如果超时，计数重置为 1，下次循环就会 break                selectCnt = 1;            &#125;             // 计数超过阈值，由 io.netty.selectorAutoRebuildThreshold 指定，默认 512            // 这是为了解决 nio 空轮询 bug            else if (SELECTOR_AUTO_REBUILD_THRESHOLD &gt; 0 &amp;&amp;                    selectCnt &gt;= SELECTOR_AUTO_REBUILD_THRESHOLD) &#123;                // 重建 selector，替换掉空轮询超过512次的selector，需要复制一些相关的信息                selector = selectRebuildSelector(selectCnt);                selectCnt = 1;                break;            &#125;            currentTimeNanos = time;        &#125;        if (selectCnt &gt; MIN_PREMATURE_SELECTOR_RETURNS) &#123;            // 记录日志        &#125;    &#125; catch (CancelledKeyException e) &#123;        // 记录日志    &#125;&#125;


ioRatio控制什么，设置为100有何作用？
​	ioTatio控制处理io时间的时间占比，如果设置成为100，则首先执行完io事件，然后执行普通任务，不会有阻塞超时，反而不能及时的处理新的io任务。

io.netty.channel.nio.NioEventLoop#run 主要任务是执行死循环，不断看有没有新任务，有没有 IO 事件
protected void run() &#123;    for (;;) &#123;        try &#123;            try &#123;                // calculateStrategy 的逻辑如下：                // 有任务，会执行一次 selectNow，清除上一次的 wakeup 结果，无论有没有 IO 事件，都会跳过 switch                // 没有任务，会匹配 SelectStrategy.SELECT，看是否应当阻塞                switch (selectStrategy.calculateStrategy(selectNowSupplier, hasTasks())) &#123;                    case SelectStrategy.CONTINUE:                        continue;                    case SelectStrategy.BUSY_WAIT:                    case SelectStrategy.SELECT:                        // 因为 IO 线程和提交任务线程都有可能执行 wakeup，而 wakeup 属于比较昂贵的操作，因此使用了一个原子布尔对象 wakenUp，它取值为 true 时，表示该由当前线程唤醒                        // 进行 select 阻塞，并设置唤醒状态为 false                        boolean oldWakenUp = wakenUp.getAndSet(false);                                                // 如果在这个位置，非 EventLoop 线程抢先将 wakenUp 置为 true，并 wakeup                        // 下面的 select 方法不会阻塞                        // 等 runAllTasks 处理完成后，到再循环进来这个阶段新增的任务会不会及时执行呢?                        // 因为 oldWakenUp 为 true，因此下面的 select 方法就会阻塞，直到超时                        // 才能执行，让 select 方法无谓阻塞                        select(oldWakenUp);                        if (wakenUp.get()) &#123;                            selector.wakeup();                        &#125;                    default:                &#125;            &#125; catch (IOException e) &#123;                rebuildSelector0();                handleLoopException(e);                continue;            &#125;            cancelledKeys = 0;            needsToSelectAgain = false;            // ioRatio 默认是 50            final int ioRatio = this.ioRatio;            if (ioRatio == 100) &#123;                try &#123;                    processSelectedKeys();                &#125; finally &#123;                    // ioRatio 为 100 时，总是运行完所有非 IO 任务                    runAllTasks();                &#125;            &#125; else &#123;                   // 处理io事件之前记录了开始的时间                final long ioStartTime = System.nanoTime();                try &#123;                    processSelectedKeys();                &#125; finally &#123;                    // 记录 io 事件处理耗时                    final long ioTime = System.nanoTime() - ioStartTime;                    // 运行非 IO 任务，一旦超时会退出 runAllTasks                    runAllTasks(ioTime * (100 - ioRatio) / ioRatio);                &#125;            &#125;        &#125; catch (Throwable t) &#123;            handleLoopException(t);        &#125;        try &#123;            if (isShuttingDown()) &#123;                closeAll();                if (confirmShutdown()) &#123;                    return;                &#125;            &#125;        &#125; catch (Throwable t) &#123;            handleLoopException(t);        &#125;    &#125;&#125;

⚠️ 注意
这里有个费解的地方就是 wakeup，它既可以由提交任务的线程来调用（比较好理解），也可以由 EventLoop 线程来调用（比较费解），这里要知道 wakeup 方法的效果：

由非 EventLoop 线程调用，会唤醒当前在执行 select 阻塞的 EventLoop 线程
由 EventLoop 自己调用，会本次的 wakeup 会取消下一次的 select 操作


